INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation, order_index) VALUES
('5490e9b2-f3a1-4a92-9ed1-13dd36fb034a', 'Bạn hỏi ''Where can I buy some stamps?'', người ta sẽ khuyên đi đâu?', 'multiple_choice', '["At the police station.","At the post office.","At the hospital.","At the restaurant."]'::jsonb, 'At the post office.', 'Tem (''stamps'') được bán tại bưu điện (''post office'').', 3),
('400ab212-bf68-4c17-9407-3aa902b939a7', 'Bồi bàn hỏi ''Are you ready to order?'' Bạn muốn gọi bít tết, trả lời thế nào?', 'multiple_choice', '["Yes, I''ll have the steak.","No, I am not ready.","Yes, I like beef.","I don''t know."]'::jsonb, 'Yes, I''ll have the steak.', 'Cấu trúc ''I''ll have...'' là cách phổ biến để gọi món.', 1),
('400ab212-bf68-4c17-9407-3aa902b939a7', 'Dùng bữa xong và muốn thanh toán, bạn gọi phục vụ và nói gì?', 'multiple_choice', '["Could I have the bill, please?","Where is the money?","I want to pay you.","Give me the paper."]'::jsonb, 'Could I have the bill, please?', '''The bill'' là hóa đơn thanh toán bữa ăn.', 2),
('400ab212-bf68-4c17-9407-3aa902b939a7', 'Khi mang đồ ăn ra bàn, bồi bàn thường chúc câu gì?', 'multiple_choice', '["Good luck.","Enjoy your meal.","Have a good trip.","Sleep well."]'::jsonb, 'Enjoy your meal.', '''Enjoy your meal'' là lời chúc ngon miệng.', 3),
('16bc0959-15c1-4740-bbb0-e496e9500104', 'Trong câu ''I can swim'', từ ''can'' thường được phát âm lướt ở dạng yếu là gì?', 'multiple_choice', '["/kæn/","/kən/","/kɑːn/","/kɪn/"]'::jsonb, '/kən/', 'Dạng yếu (không nhấn) của ''can'' là /kən/.', 1),
('16bc0959-15c1-4740-bbb0-e496e9500104', 'Khi trả lời ''Yes, I can'', từ ''can'' ở cuối câu phải phát âm ở dạng mạnh là gì?', 'multiple_choice', '["/kən/","/kæn/","/kʌn/","/kɒn/"]'::jsonb, '/kæn/', 'Đứng cuối câu trả lời ngắn, ''can'' được nhấn mạnh thành /kæn/.', 2),
('16bc0959-15c1-4740-bbb0-e496e9500104', 'Giới từ ''to'' trong ''go to school'' thường bị đọc lướt thành âm nào?', 'multiple_choice', '["/tuː/","/tə/","/tiː/","/taɪ/"]'::jsonb, '/tə/', 'Âm /u:/ trong ''to'' thường biến thành âm schwa /ə/ (/tə/) để đọc nhanh.', 3),
('218d9a71-421a-4ee5-afe6-486edff31282', 'Khi đọc nhanh ''ten boys'', đồng hóa âm làm âm /n/ biến đổi thành âm nào?', 'multiple_choice', '["/m/","/ŋ/","/l/","/p/"]'::jsonb, '/m/', 'Âm /n/ bị ảnh hưởng bởi /b/, biến thành /m/ -> ''tem boys''.', 1),
('218d9a71-421a-4ee5-afe6-486edff31282', 'Cụm ''good boy'' khi nói nhanh, âm /d/ có thể bị đồng hóa thành âm gì?', 'multiple_choice', '["/t/","/g/","/b/","/m/"]'::jsonb, '/b/', 'Âm /d/ bị ảnh hưởng bởi /b/ biến thành /b/ -> ''goob boy''.', 2),
('218d9a71-421a-4ee5-afe6-486edff31282', 'Mục đích chính của hiện tượng đồng hóa âm (Assimilation) là gì?', 'multiple_choice', '["Để làm câu dài hơn","Để nói nhanh, trơn tru và ít tốn sức hơn","Để đổi nghĩa từ","Làm khó người nghe"]'::jsonb, 'Để nói nhanh, trơn tru và ít tốn sức hơn', 'Đồng hóa âm giúp các cơ quan phát âm di chuyển mượt mà.', 3),
('d1ef0ff7-abf9-457f-aaf3-becf3ac523cb', 'Đặc điểm nào KHÔNG thuộc về cách phát âm tự nhiên của người bản xứ?', 'multiple_choice', '["Nối âm","Nuốt âm","Đọc tách rời từng chữ một","Rút gọn từ"]'::jsonb, 'Đọc tách rời từng chữ một', 'Người bản xứ nói liền mạch, không tách rời từng chữ.', 1),
('d1ef0ff7-abf9-457f-aaf3-becf3ac523cb', 'Áp dụng nối âm, nuốt âm mang lại lợi ích gì?', 'multiple_choice', '["Nói chậm lại","Nói lưu loát và cải thiện kỹ năng nghe","Phát âm sai","Viết đúng chính tả"]'::jsonb, 'Nói lưu loát và cải thiện kỹ năng nghe', 'Giúp nói tự nhiên và bắt kịp tốc độ nghe người bản ngữ.', 2),
('d1ef0ff7-abf9-457f-aaf3-becf3ac523cb', 'Khi nghe ''gonna'', bạn hiểu đó là dạng rút gọn của cụm nào?', 'multiple_choice', '["go out","going to","got to","good at"]'::jsonb, 'going to', '''Gonna'' là rút gọn của ''going to''.', 3),
('b0cc9fb7-8f1d-4058-83ff-6fa5cc3a2a9d', 'Nhóm từ (Thought group) khi nói tiếng Anh có tác dụng gì?', 'multiple_choice', '["Giúp ngắt nghỉ đúng chỗ để người nghe dễ hiểu","Làm câu dài ra","Tăng âm lượng","Thay thế dấu câu"]'::jsonb, 'Giúp ngắt nghỉ đúng chỗ để người nghe dễ hiểu', 'Nhóm các từ có ý nghĩa liên quan để tạo nhịp điệu ngắt nghỉ phù hợp.', 1),
('b0cc9fb7-8f1d-4058-83ff-6fa5cc3a2a9d', 'Dấu ''/'' trong ''If it rains, / we will stay home'' biểu thị điều gì?', 'multiple_choice', '["Kết thúc câu","Chỗ ngắt giọng tự nhiên","Nhấn trọng âm","Nối âm"]'::jsonb, 'Chỗ ngắt giọng tự nhiên', 'Mô phỏng khoảng dừng ngắn (pause) giữa hai cụm ý nghĩa.', 2),
('b0cc9fb7-8f1d-4058-83ff-6fa5cc3a2a9d', 'Việc ngắt nghỉ sai chỗ (sai thought group) có thể gây hậu quả gì?', 'multiple_choice', '["Làm thay đổi hoặc sai lệch ý nghĩa của câu","Giọng hay hơn","Nói nhanh hơn","Không ảnh hưởng"]'::jsonb, 'Làm thay đổi hoặc sai lệch ý nghĩa của câu', 'Ngắt nghỉ sai làm người nghe hiểu sai cấu trúc và ý nghĩa.', 3),
('b13f5875-f8a4-4edb-8eec-d376774fed83', 'Nối âm nguyên âm - nguyên âm (V-V linking) xảy ra khi nào?', 'multiple_choice', '["Từ trước kết thúc nguyên âm, từ sau bắt đầu nguyên âm","Từ trước phụ âm, từ sau nguyên âm","Cả hai bắt đầu phụ âm","Giữa hai từ có dấu phẩy"]'::jsonb, 'Từ trước kết thúc nguyên âm, từ sau bắt đầu nguyên âm', 'Đây là nguyên lý cơ bản của V-V linking.', 1),
('b13f5875-f8a4-4edb-8eec-d376774fed83', 'Nối âm cụm ''go out'', người bản xứ thường chèn âm gì ở giữa?', 'multiple_choice', '["/j/","/r/","/w/","/l/"]'::jsonb, '/w/', 'Chu môi từ /oʊ/ sang /aʊ/ tạo ra âm /w/ (/goʊ waʊt/).', 2),
('b13f5875-f8a4-4edb-8eec-d376774fed83', 'Trong cụm ''see it'', âm chèn nào thường xuất hiện để nối?', 'multiple_choice', '["/w/","/t/","/s/","/j/"]'::jsonb, '/j/', 'Từ âm bẹt /i:/ sang /ɪ/ tạo ra âm /j/ ở giữa.', 3),
('af9f5e2c-4519-4a91-b981-e3e852187324', 'Nối âm phụ âm - nguyên âm phổ biến nhất khi nào?', 'multiple_choice', '["Từ trước kết thúc phụ âm, từ sau bắt đầu nguyên âm","Từ trước kết thúc nguyên âm","Cả hai kết thúc phụ âm","Cả hai bắt đầu nguyên âm"]'::jsonb, 'Từ trước kết thúc phụ âm, từ sau bắt đầu nguyên âm', 'Phụ âm cuối từ trước luyến sang nguyên âm đầu từ sau.', 1);